    }

    let mut msg2 = Message::new("user_bob");
    msg2.add_encrypted_key(&String::from("timestamp_check"), &[]).ok();
    println!("Message 2 payload count: {}", msg2.payload.len());
}

use std::fs;
use std::path::{Path, PathBuf};

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let start_dir = Path::new("./test_data");
    if !start_dir.exists() {
        println!("Please create a directory named 'test_data' for this example.");
        return Ok(())
    }

    fn search_recursively(current_path: &Path) -> Result<i32, std::io::Error> {
        let mut count = 0;
        for entry in fs::read_dir(current_path)? {
            let entry = entry?;
            let path = entry.path();
            if path.is_dir() {
                count += search_recursively(&path)?;
            } else if path.extension().map_or(false, |ext| ext == "txt") {
                let content = fs::read_to_string(&path)?;
                if content.contains("SECRET_KEY") {
                    println!("Found match in: {}", path.display());
                    count += 1;
                }
            }
        }
        Ok(count)
    }

    let total_matches = search_recursively(start_dir)?;
    println!("nSearch complete. Total matches found: {}", total_matches);
    Ok(())
}

use std::collections::HashMap;
#[derive(Eq, Hash, PartialEq)]
struct CacheKey(String);
struct RecordData(String);

struct DnsResolver {
    cache: HashMap<CacheKey, RecordData>,
}

impl DnsResolver {
    fn new() -> Self {
        DnsResolver { cache: HashMap::new() }
    }

    fn resolve_record(&mut self, hostname: &str) -> Option<String> {
        let key = CacheKey(hostname.to_owned());
        if let Some(data) = self.cache.get(&key) {
            return Some(format!("Cached result for {}", data.0));
        }

        println!("Performing network lookup for {}", hostname);

        let simulated_result = format!("Successfully found IP records for {}", hostname);
        self.cache.insert(key, RecordData(simulated_result.clone()));
        Some(simulated_result)
    }
}

fn main() {
    let mut resolver = DnsResolver::new();

    if let Some(result1) = resolver.resolve_record("example.com") {
        println!("Result 1: {}", result1);
    }

    if let Some(result2) = resolver.resolve_record("google.net") {
        println!("Result 2: {}", result2);
    }

    if let Some(result3) = resolver.resolve_record("example.com") {
        println!("Result 3: {}", result3);
    }
}

use std::collections::HashMap;

struct FeatureStore {
    state: HashMap<String, String>,
}

impl FeatureStore {
    fn new() -> Self {
        FeatureStore { state: HashMap::new() }
    }

    fn process_event(&mut self, key: &str, event_data: &str) -> Result<(), &'static str> {
        if !self.state.contains_key(key) {
            return Err("Feature not initialized for this key");
        }

        let current_value = self.state.get(key).unwrap().to_string();
        println!("Processing event for {}: Old state: {}", key, current_value);

        // Simulate complex logic that needs macro expansion in a real scenario
        let new_computed_value = format!("{}-processed-by-{}", current_value, event_data);

        self.state.insert(key.to_string(), new_computed_value);
        Ok(())
    }

    fn get_embedding(&self, key: &str) -> Option<&String> {
        self.state.get(key)
    }
}

fn main() {
    let mut store = FeatureStore::new();
    store.state.insert("user_session".to_string(), "initial_value".to_string());

    if let Err(e) = store.process_event("user_session", "device_boot") {
        println!("Error: {}", e);
    }

    if let Ok(_) = store.process_event("user_session", "network_change") {
        println!("Successfully updated state.");
    }

    match store.get_embedding("user_session") {
        Some(embed) => println!("Final Embedding: {}", embed), 
        None => println!("Embedding not found.")
    }
}

use std::collections::HashMap;
use std::hash::{Hash, Hasher};

struct SystemState {
    last_processed_id: u32,
    event_count: usize,
}

impl Default for SystemState {
    fn default() -> Self {
        SystemState { last_processed_id: 0, event_count: 0 }
    }
}

struct EventProcessor {
    state: SystemState,
}

impl EventProcessor {
    fn new() -> Self {
        EventProcessor { state: SystemState::default() }
    }

    fn handle_event(&mut self, event_data: u32) -> bool {
        if event_data <= self.state.last_processed_id {
            return false;
        }

        self.state.last_processed_id = event_data;
        self.state.event_count += 1;
        println!("Successfully processed event ID: {}", event_data);
        true
    }

    fn check_for_stale_events(&mut self, current_time: u32) -> bool {
        if current_time > self.state.last_processed_id + 100 {
            println!("Detected significant time gap or state change.");
            self.state.event_count += 1;
            true
        } else {
            false
        }
    }
}

fn main() {
    let mut processor = EventProcessor::new();

    processor.handle_event(10);
    processor.handle_event(25);

    println!("nChecking for background state changes...");
    let processed = processor.check_for_stale_events(300);
    if processed {
        println!("State required manual synchronization.");
    }

    processor.handle_event(100); 
}
